#!runts
import {create,PathRef} from "../immer-path-ref.js";
import {ref,Ref} from "@hoge1e3/ref";
import * as assert from "assert";
type Item={
    title:string,
    sub?: Item[],
};
export async function main(){
    const root:Item={
        title:"test",
        sub:[
            {title:"sub1"},
            {title:"sub2",
                sub:[
                    {title:"subsub"}
                ],
            },
        ],
    };
    const rr=ref(root)
    const rootRef:PathRef<Item>=create(rr);
    rootRef.on("change",(e)=>{
      console.log("r",e)
    })
    console.log("v0",rootRef.value);
    //return;
    const r1=rootRef.join("title");
    r1.value="TITLE!";
    console.log("v1",rootRef.value);
    console.log("v1",rr.value);
    
    const r1s=rootRef.join("sub") as any as PathRef<Item[]>;
    const r2=r1s.join(1);
    r2.value={title:"sub3"};
    console.log("v3",rootRef.value);
    
}    
